package operators;

public class Unaryoperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//unary operators are +,-,++,--
				int a=5;
				System.out.println(a);
				System.out.println(+a);
				System.out.println(-a);
				System.out.println(a);
				System.out.println(++a);
				System.out.println(a++);
				System.out.println(a);
				System.out.println(--a);
				System.out.println(a);
				System.out.println(a--);
				System.out.println(a);

	}

}
